INSERT OR IGNORE INTO ec_posts (id, slug, status, created_at, updated_at, published_at, locale, title, content, excerpt) 
VALUES (
    'post-signs-of-hidden-water-leaks', 
    'signs-of-hidden-water-leaks', 
    'published', 
    '2026-04-20T17:45:13.264Z', 
    '2026-04-20T17:45:13.264Z', 
    '2026-04-20T17:45:13.264Z', 
    'he', 
    '5 סימנים שיש לכם נזילה סמויה בבית', 
    '{"title":"5 סימנים שיש לכם נזילה סמויה בבית","excerpt":"נזילות סמויות יכולות לגרום לנזקים של אלפי שקלים לפני שאתם בכלל מבינים שיש בעיה. למדו לזהות את הסימנים המוקדמים ולחסוך הרבה כסף וכאב ראש.","content":[{"title":"למה נזילות סמויות כל כך מסוכנות?","body":"נזילה סמויה היא נזילה שמתרחשת בתוך הקירות, הרצפה או מתחת לאריחים — ואתם לא רואים אותה ישירות. בישראל, הבעיה נפוצה במיוחד בגלל מים קשים שמשחקים עם הצנרת לאורך זמן. מים שדולפים לאיטם גורמים לעובש, לנזקי מבנה ולעלייה משמעותית בחשבון המים."},{"title":"סימן 1: עלייה פתאומית בחשבון המים","body":"אם חשבון המים עלה בפתאומיות מבלי שהרגליכם השתנו, זה אחד הסימנים הברורים ביותר לנזילה. השוו את החשבונות החודשיים האחרונים. עלייה של יותר מ-20-30% ללא סיבה ברורה — הגיע הזמן לבדוק."},{"title":"סימן 2: כתמי לחות או קילוף צבע","body":"כתמים צהובים-חומים על הקירות, תקרה קמורה, או צבע שמתקלף הם סימנים קלאסיים לרטיבות מתמשכת. אל תתעלמו מהם — גם כתם קטן עלול להיות סימן לנזילה גדולה מאחוריו."},{"title":"סימן 3: ריח עובש ללא מקור ברור","body":"ריח לחות או עובש שלא נעלם גם לאחר אוורור הוא אות אדום. עובש מתפתח מהר מאוד במקומות לחים, ויכול לגרום לבעיות בריאות חמורות — בעיקר לילדים ולאנשים עם אסטמה."},{"title":"סימן 4: רצפה או קירות שמרגישים רטובים","body":"אם אתם מרגישים שהרצפה קצת רטובה מתחת לאריחים, או שהקיר מרגיש קר ולח באופן לא רגיל, זה עלול להיות נזילה תת-קרקעית. זו בעיה שדורשת מומחה עם ציוד איתור מקצועי."},{"title":"סימן 5: מד המים זזה כשכל הברזים סגורים","body":"בדיקה פשוטה: סגרו את כל ברזי הבית ובדקו את מד המים. אם המחוג זזה — יש נזילה. ציינו את המספר, המתינו 10 דקות ובדקו שוב. אם המספר השתנה, קראו לאינסטלטור מיד."}],"tips":["בצעו בדיקת מד מים אחת לחודש — לוקח שתי דקות ויכול לחסוך אלפים","אחסנו תמונות של מצב הקירות שלכם לאורך זמן — ישקף שינויים","קנו גלאי לחות זול מהרשת — שוות זהב לאיתור מוקד","בדקו מתחת לכיורים ומאחורי האסלה פעם בחצי שנה"],"faqs":[{"question":"כמה עולה לאתר נזילה סמויה?","answer":"איתור נזילה סמויה עם ציוד מקצועי עולה בדרך כלל 300-600 ש\"ח, תלוי במורכבות. זה הרבה יותר זול מנזקי המבנה שנזילה לא מטופלת יכולה לגרום."},{"question":"האם ביטוח הבית מכסה נזילות סמויות?","answer":"רוב פוליסות ביטוח הבית כוללות כיסוי לנזקי מים מנזילות סמויות, אך עם מגבלות ותאריכי דיווח. כדאי לבדוק את הפוליסה שלכם ולדווח מהר ככל האפשר."},{"question":"כמה זמן לוקח לתקן נזילה סמויה?","answer":"תלוי מאוד במיקום ובחומרה. נזילה פשוטה יכולה להיות מטופלת תוך שעה-שעתיים. נזילה בצנרת ראשית בתוך קיר עלולה לקחת יום-יומיים כולל ייבוש."}],"date":"12 באפריל 2026","category":"נזילות מים","readTime":5}',
    'נזילות סמויות יכולות לגרום לנזקים של אלפי שקלים לפני שאתם בכלל מבינים שיש בעיה. למדו לזהות את הסימנים המוקדמים ולחסוך הרבה כסף וכאב ראש.'
);

INSERT OR IGNORE INTO ec_posts (id, slug, status, created_at, updated_at, published_at, locale, title, content, excerpt) 
VALUES (
    'post-how-to-prevent-sink-clogs', 
    'how-to-prevent-sink-clogs', 
    'published', 
    '2026-04-20T17:45:13.264Z', 
    '2026-04-20T17:45:13.264Z', 
    '2026-04-20T17:45:13.264Z', 
    'he', 
    'איך למנוע סתימות בכיור — 7 הרגלים שכל בעל בית צריך', 
    '{"title":"איך למנוע סתימות בכיור — 7 הרגלים שכל בעל בית צריך","excerpt":"כיור סתום הוא אחד הטרדות הנפוצות ביותר בבית. הבשורה הטובה: 90% מהסתימות ניתן למנוע לגמרי עם כמה הרגלים פשוטים. הנה המדריך המלא.","content":[{"title":"למה כיורים נסתמים — הסיבות האמיתיות","body":"כיורי מטבח נסתמים בעיקר בגלל שומן, שאריות מזון וקפה טחון. כיורי אמבטיה — בגלל שיער ושאריות סבון. ברגע שאתם מבינים את האויב, קל הרבה יותר להתמודד איתו."},{"title":"הרגל 1: לעולם אל תשפכו שומן לכיור","body":"שומן מתבשיל מתקשה בצינורות כמו נר. במהלך השנים הוא מצטבר ויוצר פקק עבה שמושך אליו חלקיקים נוספים. שפכו שומן לצנצנת ישנה ואחר כך לפח — זה ההרגל שישמור את הצנרת שלכם הכי הרבה זמן."},{"title":"הרגל 2: מסננת — השקעה הכי משתלמת שתעשו","body":"מסננת ניקוז טובה עולה 10-30 ש\"ח ומונעת קריאת אינסטלטור של מאות שקלים. השתמשו במסננת בכל כיור ומקלחת, ונקו אותה אחרי כל שימוש. פשוט, יעיל, חוסך כסף."},{"title":"הרגל 3: מים רותחים — הניקוי השבועי","body":"פעם בשבוע, שפכו קומקום מלא של מים רותחים לכיור המטבח לאחר שטיפת הכלים. המים הרותחים ממיסים את השומן הצבור ומנקים את הדפנות לפני שהוא מספיק להתקשות."},{"title":"הרגל 4: סודה + חומץ פעם בחודש","body":"שפכו חצי כוס סודה לשתייה לניקוז, ואחריה חצי כוס חומץ לבן. תשמעו בועות — זה עובד! המתינו 20 דקות ושטפו במים רותחים. ניקוי טבעי, לא פוגע בצנרת ומצוין לתחזוקה שוטפת."},{"title":"הרגל 5: אל תשפכו שאריות קפה לכיור","body":"קפה טחון הוא אחד הגורמים הנפוצים לסתימות כיור מטבח. הוא לא נמס במים ומצטבר יחד עם השומן. תמיד שפכו קפה לפח."},{"title":"הרגל 6: בדקו את הסיפון אחת לשנה","body":"הסיפון (צינור ה-U מתחת לכיור) הוא המקום הנפוץ ביותר לסתימות. פעם בשנה, פתחו אותו עם דלי מתחת, נקו אותו והרכיבו בחזרה. לוקח 10 דקות ומונע כאבי ראש."},{"title":"הרגל 7: אל תיכנסו לפאניקה — פומפה לפני אינסטלטור","body":"לפני שאתם מתקשרים, נסו פומפה (פלנג''ר) — הכלי הכי יעיל לסתימות קלות עד בינוניות. עבדו עם תנועות מהירות 15-20 פעמים. ברוב המקרים זה יפתור את הבעיה."}],"tips":["רכשו מסננת לכל כיור בבית — השקעה חד-פעמית קטנה","שמרו סודה לשתייה וחומץ בבית לתחזוקה חודשית","הדרכת ילדים לגבי מה לא לשפוך לכיור — הכי חשוב!"],"date":"28 במרץ 2026","category":"תחזוקה מונעת","readTime":4}',
    'כיור סתום הוא אחד הטרדות הנפוצות ביותר בבית. הבשורה הטובה: 90% מהסתימות ניתן למנוע לגמרי עם כמה הרגלים פשוטים. הנה המדריך המלא.'
);

INSERT OR IGNORE INTO ec_posts (id, slug, status, created_at, updated_at, published_at, locale, title, content, excerpt) 
VALUES (
    'post-when-to-replace-solar-water-heater', 
    'when-to-replace-solar-water-heater', 
    'published', 
    '2026-04-20T17:45:13.264Z', 
    '2026-04-20T17:45:13.264Z', 
    '2026-04-20T17:45:13.264Z', 
    'he', 
    'מתי להחליף דוד שמש — הסימנים שאל תתעלמו מהם', 
    '{"title":"מתי להחליף דוד שמש — הסימנים שאל תתעלמו מהם","excerpt":"דוד שמש טוב יכול להחזיק 15-20 שנה, אך ישנם סימנים ברורים שמעידים שהגיע הזמן להחלפה. כדאי לדעת מה לחפש לפני שהוא מפסיק לעבוד לגמרי — ותישארו בלי מים חמים.","content":[{"title":"מה תוחלת החיים של דוד שמש?","body":"דוד שמש ישראלי טיפוסי מחזיק בין 12 ל-20 שנה, תלוי באיכות הציוד ובתחזוקה. גב השמש (הקולקטור) בדרך כלל מחזיק יותר זמן מהמיכל עצמו. בדקו מתי הותקן הדוד שלכם — זה המידע הכי חשוב."},{"title":"סימן 1: מים לא מספיק חמים","body":"אם המים לא מגיעים לטמפרטורה שאתם רגילים אליה, גם בימים שמשיים, זה סימן שיש בעיה. ייתכן שזו תקלה בכדור הניתן לתיקון, אך לדוד ישן — לרוב זה סימן שהגיע הזמן."},{"title":"סימן 2: חלודה ורטיבות בסביבת הדוד","body":"חלודה על המיכל, על הצנרת שמסביב, או כתמי לחות על התקרה מתחת לדוד — אלה סימני אזהרה רציניים. חלודה בדוד היא בדרך כלל לא ניתנת לתיקון וגוררת החלפה."},{"title":"סימן 3: רעשים חריגים","body":"בועות, הקשות, או רעשי זרימה חריגים בדוד הם סימן להצטברות אבנית, תקלה בתרמוסטט, או בעיה בגוף החימום החשמלי. חלק מהרעשים ניתנים לתיקון — אך כדאי לבדוק עם מקצוען."},{"title":"מה עדיף — תיקון או החלפה?","body":"הכלל הפשוט: אם הדוד מעל 12 שנה ועולה לתקן אותו יותר מ-40% ממחיר דוד חדש — תחליפו. דוד חדש יעיל בהרבה מבחינת אנרגיה, ויחסוך לכם כסף בטווח הארוך."},{"title":"כמה עולה להחליף דוד שמש?","body":"החלפת דוד שמש כולל גב שמש חדש עולה בדרך כלל 2,500-5,000 ש\"ח, תלוי בגודל ובמותג. ניתן לקבל מענקים מהמדינה דרך רשות החשמל — מומלץ לבדוק זכאות לפני רכישה."}],"faqs":[{"question":"האם ניתן לתקן דוד שמש שדולף?","answer":"תלוי במיקום הנזילה. נזילה בצנרת — לרוב תיקון פשוט. נזילה מהמיכל עצמו — לרוב מצריכה החלפת מיכל או דוד שלם."},{"question":"כמה זמן לוקח להתקין דוד שמש חדש?","answer":"התקנת דוד שמש חדש על גג קיים לוקחת בדרך כלל 3-6 שעות. אם יש צורך בשיפוץ גג או חיזוק מבנה — עלול לקחת יותר."}],"date":"15 במרץ 2026","category":"דוד שמש","readTime":6}',
    'דוד שמש טוב יכול להחזיק 15-20 שנה, אך ישנם סימנים ברורים שמעידים שהגיע הזמן להחלפה. כדאי לדעת מה לחפש לפני שהוא מפסיק לעבוד לגמרי — ותישארו בלי מים חמים.'
);

INSERT OR IGNORE INTO ec_posts (id, slug, status, created_at, updated_at, published_at, locale, title, content, excerpt) 
VALUES (
    'post-what-to-do-pipe-burst', 
    'what-to-do-pipe-burst', 
    'published', 
    '2026-04-20T17:45:13.264Z', 
    '2026-04-20T17:45:13.264Z', 
    '2026-04-20T17:45:13.264Z', 
    'he', 
    'פיצוץ צינור — מה לעשות בשלוש הדקות הראשונות', 
    '{"title":"פיצוץ צינור — מה לעשות בשלוש הדקות הראשונות","excerpt":"פיצוץ צינור הוא מצב חירום שכל דקה שנייה חשובה. פעולה נכונה ומהירה יכולה למנוע נזק של עשרות אלפי שקלים. הנה המדריך לפעולה מהירה ונכונה.","content":[{"title":"שניה לפני — דעו איפה ברז הניתוק הראשי","body":"הדבר הכי חשוב שאתם יכולים לעשות עכשיו, לפני שיש בעיה: מצאו את ברז הניתוק הראשי בדירה שלכם. בדרך כלל הוא נמצא ליד מד המים — ליד הכניסה לדירה, במרפסת, או בממ\"ד. סמנו אותו לאתם ולכל בני המשפחה."},{"title":"דקה 1: סגרו את ברז הניתוק הראשי","body":"ברגע שיש פיצוץ צינור — לא מחפשים, לא בודקים, לא מתקשרים. קודם כל: ברז ניתוק ראשי. סגירתו תעצור את זרימת המים לכל הדירה ותמנע את הנזק מלהתרחב. זאת הפעולה הכי חשובה."},{"title":"דקה 2: כבו את החשמל אם יש מים ליד שקעים","body":"מים וחשמל הם שילוב מסוכן. אם המים הגיעו לאזור שקעים או לוח חשמל — כבו את הפסק הראשי בארגז החשמל ואל תיגעו בשקעים. בטיחות קודם לכל."},{"title":"דקה 3: התקשרו לאינסטלטור חירום ואז לביטוח","body":"עכשיו קראו לאינסטלטור חירום. אחרי שהזמנתם אינסטלטור — צלמו את הנזק ודווחו לחברת הביטוח. תיעוד מוקדם חיוני לתביעה."},{"title":"מה לעשות בזמן ההמתנה לאינסטלטור","body":"פנו רהיטים וחפצים אישיים מהאזור המוצף. הניחו מגבות ודליים לספוג מים. פתחו חלונות לאוורור. אל תחזרו לחשמל עד שהאזור יבש ומאושר על ידי מקצוען."}],"tips":["שמרו את מספר אינסטלטור החירום בטלפון עכשיו — לפני שצריכים","לימדו כל בן משפחה בוגר איפה ברז הניתוק הראשי","צלמו את ברז הניתוק וקראו לתמונה ''ברז ראשי'' — תמצאו אותה בשנייה"],"faqs":[{"question":"האם ביטוח הבית מכסה פיצוץ צינור?","answer":"ברוב המקרים כן — פיצוץ צינור מכוסה תחת ''נזקי מים פתאומיים''. חשוב לתעד את הנזק לפני ניקיון ולדווח מהר ככל האפשר."},{"question":"כמה עולה תיקון פיצוץ צינור?","answer":"הטווח רחב — 500 ש\"ח עד אלפי שקלים, תלוי בסוג הצינור, מיקומו ובנזקי הלוואי. ביטוח טוב יכסה את רוב הסכום."}],"date":"5 במרץ 2026","category":"חירום","readTime":3}',
    'פיצוץ צינור הוא מצב חירום שכל דקה שנייה חשובה. פעולה נכונה ומהירה יכולה למנוע נזק של עשרות אלפי שקלים. הנה המדריך לפעולה מהירה ונכונה.'
);

INSERT OR IGNORE INTO ec_posts (id, slug, status, created_at, updated_at, published_at, locale, title, content, excerpt) 
VALUES (
    'post-annual-plumbing-maintenance-checklist', 
    'annual-plumbing-maintenance-checklist', 
    'published', 
    '2026-04-20T17:45:13.264Z', 
    '2026-04-20T17:45:13.264Z', 
    '2026-04-20T17:45:13.264Z', 
    'he', 
    'צ''קליסט תחזוקת אינסטלציה שנתי — 12 דברים לבדוק לפני החורף', 
    '{"title":"צ''קליסט תחזוקת אינסטלציה שנתי — 12 דברים לבדוק לפני החורף","excerpt":"חורף ישראלי עלול להיות קשה על מערכות האינסטלציה בבית. הכינו את הבית לפני שמתחיל הגשם עם צ''קליסט פשוט שיחסוך לכם הוצאות גדולות.","content":[{"title":"למה תחזוקה מונעת שווה כסף","body":"הנתון שמפתיע אנשים: עלות תחזוקה שנתית מקצועית היא בסביבות 300-500 ש\"ח. עלות תיקון נזק ממוצע שניתן היה למנוע — כ-2,000 ש\"ח ויותר. החשבון פשוט."},{"title":"בדיקות ניקוז וצנרת","body":"בדקו שכל ניקוזים זורמים בחופשיות. נקו מסננות וניקוזים על הגג לפני עונת הגשמים. בדקו צינורות חיצוניים לחלודה ונזילות. ודאו שאין עצים שמסתמנים לחדור לביוב."},{"title":"בדיקות אסלה וכיורים","body":"בצעו בדיקת נזילה אסלה: הוסיפו כמה טיפות צבע מאכל לבית הגלימה. המתינו 15 דקות מבלי למשוך. אם הצבע מגיע לאגן — יש נזילה. בדקו שכל ברזים לא מטפטפים."},{"title":"בדיקות דוד שמש","body":"בדקו את הדוד ואת הצינורות שאליו לחלודה. ודאו שאין נזילות בחיבורים. בדקו שלחות החשמלי פועל כראוי לימות הגשם. נקו את הלוח השמשי לפי הצורך."},{"title":"מה לעשות בסיום הבדיקות","body":"תעדו מה בדקתם ומה מצאתם. צלמו מקומות חשודים. תקנו בעיות קלות לפני שהחורף מגיע. לבעיות שאינכם בטוחים לגביהן — כדאי להזמין ביקור תחזוקה שנתי עם אינסטלטור מקצועי."}],"tips":["קבעו תזכורת שנתית בלוח השנה: ''בדיקת אינסטלציה — לפני החורף''","תעדו כל בעיה שמוצאים — עוזר לאינסטלטור להבין את ההיסטוריה","בדקו את ביטוח הבית לפני החורף — ודאו שהכיסוי מתאים"],"date":"20 בפברואר 2026","category":"תחזוקה מונעת","readTime":5}',
